1002		// =========================================================================
1003		// Prompting
1004		// =========================================================================
1005	
1006		/**
1007		 * Send a prompt to the agent.
1008		 * - Handles extension commands (registered via pi.registerCommand) immediately, even during streaming
1009		 * - Expands file-based prompt templates by default
1010		 * - During streaming, queues via steer() or followUp() based on streamingBehavior option
1011		 * - Validates model and API key before sending (when not streaming)
1012		 * @throws Error if streaming and no streamingBehavior specified
1013		 * @throws Error if no model selected or no API key available (when not streaming)
1014		 */
1015		async prompt(text: string, options?: PromptOptions): Promise<void> {
1016			const expandPromptTemplates = options?.expandPromptTemplates ?? true;
1017	
1018			// Handle extension commands first (execute immediately, even during streaming)
1019			// Extension commands manage their own LLM interaction via pi.sendMessage()
1020			if (expandPromptTemplates && text.startsWith("/")) {
1021				const handled = await this._tryExecuteExtensionCommand(text);
1022				if (handled) {
1023					// Extension command executed, no prompt to send
1024					return;
1025				}
1026			}
1027	
1028			// Emit input event for extension interception (before skill/template expansion)
1029			let currentText = text;
1030			let currentImages = options?.images;
1031			if (this._extensionRunner?.hasHandlers("input")) {
1032				const inputResult = await this._extensionRunner.emitInput(
1033					currentText,
1034					currentImages,
1035					options?.source ?? "interactive",
1036				);
1037				if (inputResult.action === "handled") {
1038					return;
1039				}
1040				if (inputResult.action === "transform") {
1041					currentText = inputResult.text;
1042					currentImages = inputResult.images ?? currentImages;
1043				}
1044			}
1045	
1046			// Expand skill commands (/skill:name args) and prompt templates (/template args)
1047			let expandedText = currentText;
1048			if (expandPromptTemplates) {
1049				expandedText = this._expandSkillCommand(expandedText);
1050				expandedText = expandPromptTemplate(expandedText, [...this.promptTemplates]);
1051			}
1052	
1053			// If streaming, queue via steer() or followUp() based on option
1054			if (this.isStreaming) {
1055				if (!options?.streamingBehavior) {
1056					throw new Error(
1057						"Agent is already processing. Specify streamingBehavior ('steer' or 'followUp') to queue the message.",
1058					);
1059				}
1060				if (options.streamingBehavior === "followUp") {
1061					await this._queueFollowUp(expandedText, currentImages);
1062				} else {
1063					await this._queueSteer(expandedText, currentImages);
1064				}
1065				return;
1066			}
1067	
1068			// Flush any pending bash messages before the new prompt
1069			this._flushPendingBashMessages();
1070	
1071			// Validate model
1072			if (!this.model) {
1073				throw new Error(
1074					"No model selected.\n\n" +
1075						`Use /login or set an API key environment variable. See ${join(getDocsPath(), "providers.md")}\n\n` +
1076						"Then use /model to select a model.",
1077				);
1078			}
1079	
1080			// Check if a higher-priority provider in the fallback chain has recovered
1081			const restoration = await this._fallbackResolver.checkForRestoration(this.model);
1082			if (restoration) {
1083				const previousProvider = `${this.model.provider}/${this.model.id}`;
1084				this.agent.setModel(restoration.model);
1085				this.sessionManager.appendModelChange(restoration.model.provider, restoration.model.id);
1086				this._emit({
1087					type: "fallback_provider_restored",
1088					provider: `${restoration.model.provider}/${restoration.model.id}`,
1089					reason: `Restored from ${previousProvider}`,
1090				});
1091			}
1092	
1093			// Validate provider readiness
1094			if (!this._modelRegistry.isProviderRequestReady(this.model.provider)) {
1095				const isOAuth = this._modelRegistry.isUsingOAuth(this.model);
1096				if (isOAuth) {
1097					throw new Error(
1098						`Authentication failed for "${this.model.provider}". ` +
1099							`Credentials may have expired or network is unavailable. ` +
1100							`Run '/login ${this.model.provider}' to re-authenticate.`,
1101					);
1102				}
1103				throw new Error(
1104					`No API key found for ${this.model.provider}.\n\n` +
1105						`Use /login or set an API key environment variable. See ${join(getDocsPath(), "providers.md")}`,
1106				);
1107			}
1108	
1109			// Check if we need to compact before sending (catches aborted responses)
